const fs = require('fs');
const path = require('path');
const { spawnSync } = require('child_process');

const repoRoot = path.resolve(__dirname, '..', '..', '..', '..');
const localTestingRoot = path.join(repoRoot, 'local testing');
const sessionFile = path.join(localTestingRoot, 'runtime', 'live-browser-session.json');
const launchScript = path.join(localTestingRoot, 'launch-live-browser.js');

function readSession() {
  try {
    return JSON.parse(fs.readFileSync(sessionFile, 'utf8'));
  } catch (_err) {
    return null;
  }
}

function wait(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function getListeningPidsForPort(port) {
  if (!Number.isInteger(port) || port <= 0) {
    return [];
  }
  const psScript = [
    `$pids = @(Get-NetTCPConnection -LocalPort ${port} -State Listen -ErrorAction SilentlyContinue | Select-Object -ExpandProperty OwningProcess -Unique)`,
    'if (-not $pids) { exit 0 }',
    '$pids | ForEach-Object { Write-Output $_ }',
  ].join('; ');
  const result = spawnSync(
    'powershell',
    ['-NoProfile', '-Command', psScript],
    {
      cwd: repoRoot,
      stdio: 'pipe',
      windowsHide: true,
      encoding: 'utf8',
    }
  );
  if (result.status !== 0) {
    return [];
  }
  return String(result.stdout || '')
    .split(/\r?\n/)
    .map((line) => Number(String(line || '').trim()))
    .filter((pid) => Number.isInteger(pid) && pid > 0);
}

function runTaskkill(pid, label) {
  if (!Number.isInteger(pid) || pid <= 0) {
    return false;
  }
  const result = spawnSync('taskkill', ['/PID', String(pid), '/T', '/F'], {
    cwd: repoRoot,
    stdio: 'pipe',
    windowsHide: true,
    encoding: 'utf8',
  });
  if (result.status === 0) {
    console.log(`Stopped ${label} process tree ${pid}.`);
    return true;
  }
  const stderr = String(result.stderr || '').trim();
  const stdout = String(result.stdout || '').trim();
  if (stderr || stdout) {
    console.log(`taskkill ${label} ${pid}: ${stderr || stdout}`);
  }
  return false;
}

async function main() {
  const passThroughArgs = process.argv.slice(2);
  const session = readSession();
  const pidsToKill = new Set();

  if (session && session.active) {
    const nodePid = Number(session.nodePid) || 0;
    const serverPid = Number(session.serverPid) || 0;
    const appPort = Number(session.port) || 5057;
    const debugPort = Number(session.debugPort) || 9223;
    [nodePid, serverPid, ...getListeningPidsForPort(appPort), ...getListeningPidsForPort(debugPort)]
      .filter((pid) => Number.isInteger(pid) && pid > 0)
      .forEach((pid) => pidsToKill.add(pid));
  } else {
    console.log('No active live browser session recorded; launching a fresh session.');
    [5057, 9223].forEach((port) => {
      getListeningPidsForPort(port).forEach((pid) => pidsToKill.add(pid));
    });
  }

  let stoppedAny = false;
  for (const pid of pidsToKill) {
    if (runTaskkill(pid, 'relaunch')) {
      stoppedAny = true;
    }
  }

  if (stoppedAny) {
    await wait(1500);
  }

  const launch = spawnSync(process.execPath, [launchScript, ...passThroughArgs], {
    cwd: localTestingRoot,
    stdio: 'inherit',
    windowsHide: false,
  });

  if (launch.status !== 0) {
    process.exit(launch.status || 1);
  }
}

main().catch((error) => {
  console.error(error instanceof Error ? error.stack : error);
  process.exit(1);
});
